import{_ as o,o as t,c as a,a3 as i}from"./chunks/framework.CRbjHCyB.js";const u=JSON.parse('{"title":"Hook Mechanism","description":"","frontmatter":{},"headers":[],"relativePath":"catter/design/hook-mechanism.md","filePath":"en/catter/design/hook-mechanism.md"}'),n={name:"catter/design/hook-mechanism.md"};function r(s,e,c,d,l,h){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="hook-mechanism" tabindex="-1">Hook Mechanism <a class="header-anchor" href="#hook-mechanism" aria-label="Permalink to &quot;Hook Mechanism&quot;">​</a></h1><p>The hook is the lowest-level component of catter. It is a shared library that gets loaded into every process spawned by the build system. Its sole job is to intercept process creation calls and rewrite them so that every child process goes through <code>catter-proxy</code> instead of executing directly.</p><p>The hook implementation is entirely platform-specific. Unix and Windows use fundamentally different interception techniques.</p><h2 id="unix-linux-and-macos-ld-preload-interception" tabindex="-1">Unix (Linux and macOS) -- LD_PRELOAD Interception <a class="header-anchor" href="#unix-linux-and-macos-ld-preload-interception" aria-label="Permalink to &quot;Unix (Linux and macOS) -- LD_PRELOAD Interception&quot;">​</a></h2><p>The Unix hook is a shared library loaded via the dynamic linker&#39;s preload mechanism:</p><ul><li><strong>Linux</strong>: <code>libcatter-hook-unix.so</code> loaded via <code>LD_PRELOAD</code></li><li><strong>macOS</strong>: <code>libcatter-hook-unix.dylib</code> loaded via <code>DYLD_INSERT_LIBRARIES</code></li></ul><h3 id="intercepted-functions" tabindex="-1">Intercepted Functions <a class="header-anchor" href="#intercepted-functions" aria-label="Permalink to &quot;Intercepted Functions&quot;">​</a></h3><p>The hook replaces all standard POSIX functions for creating new processes:</p><p><strong>exec family</strong>:</p><ul><li><code>execve()</code>, <code>execv()</code></li><li><code>execvpe()</code>, <code>execvp()</code>, <code>execvP()</code></li><li><code>execl()</code>, <code>execlp()</code>, <code>execle()</code></li></ul><p><strong>posix_spawn family</strong>:</p><ul><li><code>posix_spawn()</code></li><li><code>posix_spawnp()</code></li></ul><p>On Linux, the hook uses <code>dlsym(RTLD_NEXT, &quot;execve&quot;)</code> to obtain the original function pointer from the next library in the load order. It then provides a replacement function with the same signature. When the replacement is called, the hook can inspect and modify the arguments before optionally calling the original.</p><p>On macOS, the hook uses the <code>DYLD_INTERPOSE</code> macro to replace functions at the dyld level, which is the preferred technique on that platform.</p><h3 id="key-classes" tabindex="-1">Key Classes <a class="header-anchor" href="#key-classes" aria-label="Permalink to &quot;Key Classes&quot;">​</a></h3><p>The hook is implemented as a set of cooperating classes:</p><ul><li><strong><code>Session</code></strong> -- Reads and stores session information from the environment. Provides the proxy path and parent session ID.</li><li><strong><code>Resolver</code></strong> -- Resolves the target executable path. Handles PATH lookups, relative path resolution, and edge cases like missing executables.</li><li><strong><code>CmdBuilder</code></strong> -- Constructs the rewritten command that invokes <code>catter-proxy</code> instead of the original executable.</li><li><strong><code>EnvGuard</code></strong> -- RAII guard that scrubs the environment before the real <code>execve</code> is called. Removes catter variables and strips the hook library from <code>LD_PRELOAD</code>.</li><li><strong><code>Executor</code></strong> -- Orchestrates the interception. Validates the session, resolves the executable, builds the proxy command, cleans the environment, and calls the original function.</li><li><strong><code>Linker</code></strong> -- Abstraction for the real system call. Wraps <code>dlsym(RTLD_NEXT, ...)</code> to call the original <code>execve</code> or <code>posix_spawn</code>.</li></ul><h3 id="hook-initialization" tabindex="-1">Hook Initialization <a class="header-anchor" href="#hook-initialization" aria-label="Permalink to &quot;Hook Initialization&quot;">​</a></h3><p>The hook library is loaded via the dynamic linker&#39;s constructor mechanism (<code>__attribute__((constructor))</code> or equivalent). During initialization, the library:</p><ol><li>Sets up logging (to <code>log/catter-hook.log</code> in the catter data directory)</li><li>Is ready to intercept -- the <code>Executor</code> lazily reads session state from the environment on first interception</li></ol><h3 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h3><p>The hook reads session information from these environment variables, set by the proxy when it launches the build command:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Purpose</th></tr></thead><tbody><tr><td><code>__key_catter_proxy_path_v1</code></td><td>Absolute path to the <code>catter-proxy</code> binary</td></tr><tr><td><code>__key_catter_command_id_v1</code></td><td>Session ID of the parent process</td></tr></tbody></table><h3 id="interception-flow" tabindex="-1">Interception Flow <a class="header-anchor" href="#interception-flow" aria-label="Permalink to &quot;Interception Flow&quot;">​</a></h3><p>When any process creation function is called (e.g., <code>execve(&quot;/usr/bin/g++&quot;, argv, envp)</code>):</p><ol><li><p>The hook&#39;s replacement function is entered.</p></li><li><p><strong><code>Executor</code></strong> validates the session. If the session is invalid (missing environment variables), it builds an error command that reports the problem to the daemon.</p></li><li><p><strong><code>Resolver</code></strong> resolves the target executable to an absolute path. For functions like <code>execvp()</code> and <code>execvpe()</code>, it searches directories in <code>PATH</code>. For <code>execve()</code>, it resolves relative to the current directory.</p></li><li><p><strong><code>CmdBuilder</code></strong> constructs the proxy command:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;proxy_path&gt; -p &lt;self_id&gt; --exec &lt;resolved_path&gt; -- &lt;original_argv...&gt;</span></span></code></pre></div><p>The original <code>argv[0]</code> and all subsequent arguments are preserved after the <code>--</code> separator.</p></li><li><p><strong><code>EnvGuard</code></strong> (RAII) modifies the environment array:</p><ul><li>Removes <code>__key_catter_proxy_path_v1</code> and <code>__key_catter_command_id_v1</code></li><li>Strips the hook library name from <code>LD_PRELOAD</code> (or <code>DYLD_INSERT_LIBRARIES</code>)</li><li>If <code>LD_PRELOAD</code> becomes empty after stripping, removes it entirely</li></ul></li><li><p><strong><code>Linker</code></strong> calls the <strong>real</strong> <code>execve()</code> (obtained via <code>dlsym(RTLD_NEXT, ...)</code>) with the rewritten command.</p></li><li><p>If <code>execve</code> succeeds, it does not return (the current process image is replaced). If it fails, the hook restores <code>errno</code> and returns the error to the caller.</p></li></ol><h3 id="why-clean-the-environment" tabindex="-1">Why Clean the Environment? <a class="header-anchor" href="#why-clean-the-environment" aria-label="Permalink to &quot;Why Clean the Environment?&quot;">​</a></h3><p>This step is critical. If the hook library remained in <code>LD_PRELOAD</code> when <code>catter-proxy</code> is launched:</p><ol><li><code>catter-proxy</code> itself would be hooked</li><li>When the proxy tries to execute the actual compiler, the hook would intercept that call</li><li>The hook would rewrite it to launch another <code>catter-proxy</code></li><li>This creates <strong>infinite recursion</strong></li></ol><p>By stripping the hook from <code>LD_PRELOAD</code>, the proxy executes without interception. The proxy re-adds <code>LD_PRELOAD</code> only when it launches a command with the <code>INJECT</code> action, ensuring the hook is attached to the right processes.</p><h3 id="recursive-hooking" tabindex="-1">Recursive Hooking <a class="header-anchor" href="#recursive-hooking" aria-label="Permalink to &quot;Recursive Hooking&quot;">​</a></h3><p>Since <code>LD_PRELOAD</code> is inherited by child processes through the environment, interception is automatically recursive. Consider this build scenario:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>make</span></span>
<span class="line"><span>  -&gt; sh -c &quot;gcc main.c -o main&quot;</span></span>
<span class="line"><span>     -&gt; gcc main.c -o main</span></span>
<span class="line"><span>        -&gt; cc1 main.c -o main.s</span></span>
<span class="line"><span>        -&gt; as main.s -o main.o</span></span>
<span class="line"><span>        -&gt; ld main.o -o main</span></span></code></pre></div><p>Every process in this tree inherits <code>LD_PRELOAD</code> and gets hooked. Each invocation goes through <code>catter-proxy</code>, which asks the daemon what to do. The build system is completely unaware of the interception.</p><hr><h2 id="windows-dll-injection-and-api-hooking" tabindex="-1">Windows -- DLL Injection and API Hooking <a class="header-anchor" href="#windows-dll-injection-and-api-hooking" aria-label="Permalink to &quot;Windows -- DLL Injection and API Hooking&quot;">​</a></h2><p>The Windows hook uses a fundamentally different approach because Windows has no equivalent to <code>LD_PRELOAD</code>. Instead, catter combines:</p><ol><li><strong>DLL injection</strong> -- to load the hook library into target processes</li><li><strong>API hooking via MinHook</strong> -- to intercept <code>CreateProcess</code> calls within those processes</li></ol><h3 id="hook-dll" tabindex="-1">Hook DLL <a class="header-anchor" href="#hook-dll" aria-label="Permalink to &quot;Hook DLL&quot;">​</a></h3><p>The hook is compiled as <code>catter-hook-win64.dll</code>. It uses MinHook, a lightweight x86/x64 API hooking library that works by overwriting the first few bytes of a target function with a jump to a detour function (trampoline hooking).</p><h3 id="environment-variables-1" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables-1" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Variable</th><th>Purpose</th></tr></thead><tbody><tr><td><code>CATTER_IPC_ID</code></td><td>Session ID of the parent process</td></tr><tr><td><code>CATTER_PROXY_PATH</code></td><td>Absolute path to the <code>catter-proxy.exe</code> binary</td></tr></tbody></table><h3 id="dll-injection-process" tabindex="-1">DLL Injection Process <a class="header-anchor" href="#dll-injection-process" aria-label="Permalink to &quot;DLL Injection Process&quot;">​</a></h3><p>When <code>catter-proxy</code> (in injector mode) needs to start a build command with the hook attached:</p><ol><li><p><strong>Create the target process suspended</strong>. The proxy calls <code>CreateProcessA()</code> with the <code>CREATE_SUSPENDED</code> flag. The process is created but its main thread does not run.</p></li><li><p><strong>Set environment variables</strong>. <code>CATTER_IPC_ID</code> and <code>CATTER_PROXY_PATH</code> are set in the target process environment before creation (passed via the environment block).</p></li><li><p><strong>Allocate memory in the target process</strong>. The proxy calls <code>VirtualAllocEx()</code> to allocate a region of memory in the target process&#39;s address space.</p></li><li><p><strong>Write the DLL path</strong>. The proxy calls <code>WriteProcessMemory()</code> to write the full path of <code>catter-hook-win64.dll</code> into the allocated memory.</p></li><li><p><strong>Create a remote thread to load the DLL</strong>. The proxy tries three methods in order:</p><ul><li><code>CreateRemoteThread()</code> -- Documented Win32 API. Tried first as it is the most widely supported.</li><li><code>NtCreateThreadEx()</code> -- Undocumented NT API. Fallback that works reliably on modern Windows (Vista+).</li><li><code>RtlCreateUserThread()</code> -- Another undocumented NT API. Last resort fallback.</li></ul><p>The remote thread&#39;s entry point is <code>LoadLibraryA</code>, and its argument is the pointer to the DLL path string written in step 4. When the thread runs, it loads <code>catter-hook-win64.dll</code> into the target process.</p></li><li><p><strong>Wait for injection to complete</strong>. The proxy waits for the remote thread to finish (with a 3-second timeout).</p></li><li><p><strong>Resume the main thread</strong>. The proxy calls <code>ResumeThread()</code> to let the target process start executing. By this point, the hook DLL is loaded and its hooks are active.</p></li></ol><h3 id="hooked-windows-apis" tabindex="-1">Hooked Windows APIs <a class="header-anchor" href="#hooked-windows-apis" aria-label="Permalink to &quot;Hooked Windows APIs&quot;">​</a></h3><p>The hook DLL installs MinHook trampoline hooks on these functions during <code>DLL_PROCESS_ATTACH</code>:</p><ul><li><strong><code>CreateProcessA()</code></strong> -- ANSI version of process creation</li><li><strong><code>CreateProcessW()</code></strong> -- Wide-character version of process creation</li><li><strong><code>CreateProcessAsUserA()</code></strong> -- Passthrough (currently not rewritten)</li><li><strong><code>CreateProcessAsUserW()</code></strong> -- Passthrough (currently not rewritten)</li></ul><p>MinHook works by:</p><ol><li>Saving the first few instructions of the target function</li><li>Overwriting them with a jump to the detour function</li><li>Providing a trampoline that contains the saved instructions followed by a jump back, so the original function can still be called</li></ol><h3 id="hook-detour-logic" tabindex="-1">Hook Detour Logic <a class="header-anchor" href="#hook-detour-logic" aria-label="Permalink to &quot;Hook Detour Logic&quot;">​</a></h3><p>When <code>CreateProcessA</code> or <code>CreateProcessW</code> is called by the hooked process:</p><ol><li><p><strong>Extract the command line</strong>. The hook reads <code>lpApplicationName</code> and <code>lpCommandLine</code>.</p></li><li><p><strong>Resolve the absolute path</strong>. The hook resolves the executable using <code>resolve_abspath()</code>, which searches the program directory, current directory, System32, Windows directory, and <code>PATH</code> (matching the standard Windows search order).</p></li><li><p><strong>Rewrite the command line</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{proxy_path} -p {ipc_id} --exec {resolved_path} -- {original_cmdline}</span></span></code></pre></div><p>The <code>lpApplicationName</code> is set to <code>nullptr</code> so that the command line is parsed by <code>CreateProcess</code> normally.</p></li><li><p><strong>Call the original <code>CreateProcess</code></strong> via the MinHook trampoline with the modified command line.</p></li></ol><h3 id="key-difference-from-unix" tabindex="-1">Key Difference from Unix <a class="header-anchor" href="#key-difference-from-unix" aria-label="Permalink to &quot;Key Difference from Unix&quot;">​</a></h3><p>On Unix, <code>LD_PRELOAD</code> is an environment variable inherited automatically by all child processes. The hook is &quot;viral&quot; by default -- every subprocess gets it.</p><p>On Windows, there is no such mechanism. The hook DLL must be explicitly injected into each new process. This happens because:</p><ol><li>The hook&#39;s <code>CreateProcess</code> detour intercepts every process creation</li><li>It rewrites the command to go through <code>catter-proxy</code></li><li>When the proxy decides to execute with <code>INJECT</code> action, it performs DLL injection into the new process (create suspended, inject, resume)</li></ol><p>This means the proxy is responsible for re-injecting the hook into each generation of child processes, maintaining the recursive interception chain.</p><h3 id="dll-lifecycle" tabindex="-1">DLL Lifecycle <a class="header-anchor" href="#dll-lifecycle" aria-label="Permalink to &quot;DLL Lifecycle&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DLL_PROCESS_ATTACH:</span></span>
<span class="line"><span>  MH_Initialize()       -- Initialize MinHook</span></span>
<span class="line"><span>  MH_CreateHook(...)    -- Install hooks on CreateProcess variants</span></span>
<span class="line"><span>  MH_EnableHook(...)    -- Activate all hooks</span></span>
<span class="line"><span></span></span>
<span class="line"><span>DLL_PROCESS_DETACH:</span></span>
<span class="line"><span>  MH_DisableHook(...)   -- Deactivate all hooks</span></span>
<span class="line"><span>  MH_Uninitialize()     -- Clean up MinHook</span></span></code></pre></div><p><code>DisableThreadLibraryCalls()</code> is called during attach to suppress <code>DLL_THREAD_ATTACH</code> and <code>DLL_THREAD_DETACH</code> notifications, reducing overhead.</p><h2 id="platform-comparison" tabindex="-1">Platform Comparison <a class="header-anchor" href="#platform-comparison" aria-label="Permalink to &quot;Platform Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Linux</th><th>macOS</th><th>Windows</th></tr></thead><tbody><tr><td>Hook library</td><td><code>libcatter-hook-unix.so</code></td><td><code>libcatter-hook-unix.dylib</code></td><td><code>catter-hook-win64.dll</code></td></tr><tr><td>Injection method</td><td><code>LD_PRELOAD</code> env var</td><td><code>DYLD_INSERT_LIBRARIES</code> env var</td><td><code>VirtualAllocEx</code> + <code>LoadLibraryA</code></td></tr><tr><td>Interposition</td><td><code>dlsym(RTLD_NEXT, ...)</code></td><td><code>DYLD_INTERPOSE</code> macro</td><td>MinHook trampoline hooking</td></tr><tr><td>Intercepted APIs</td><td><code>execve</code>, <code>execvp</code>, <code>posix_spawn</code>, etc.</td><td>Same as Linux</td><td><code>CreateProcessA</code>, <code>CreateProcessW</code></td></tr><tr><td>Recursive hooking</td><td>Automatic (env inherited)</td><td>Automatic (env inherited)</td><td>Explicit (DLL re-injected per process)</td></tr><tr><td>Env vars for session</td><td><code>__key_catter_proxy_path_v1</code>, <code>__key_catter_command_id_v1</code></td><td>Same as Linux</td><td><code>CATTER_PROXY_PATH</code>, <code>CATTER_IPC_ID</code></td></tr></tbody></table>`,63)])])}const m=o(n,[["render",r]]);export{u as __pageData,m as default};
